      },
      {
        "from": "CartService",
        "to": "PaymentService",
        "status": "risk",
        "issue": "Circuit breaker exists (good), but PaymentService's external gateway timeout is 8s while CartService's timeout on PaymentService is 5s. CartService will always timeout before PaymentService gets a gateway response on slow calls. This means CartService thinks the payment failed, but PaymentService may still receive a success from the gateway — creating a paid-but-not-recorded state."
      },
      {
        "from": "OrderService",
        "to": "InventoryService",
        "status": "risk",
        "issue": "1 retry on timeout is reasonable, but worst-case latency is 6s (3s × 2). Since CartService allows only 5s, the retry will be killed mid-flight by CartService's timeout. The retry is effectively useless under slow-InventoryService conditions."
      },
      {
        "from": "PaymentService",
        "to": "External Payment Gateway",
        "status": "risk",
        "issue": "No circuit breaker on the external payment gateway. A degraded gateway will cause every PaymentService request to hang for 8s, exhausting connection pools. PaymentService becomes a liability that propagates gateway failures upstream."
      },
      {
        "from": "CartService",
        "to": "OrderService → PaymentService (sequential)",
        "status": "broken",
        "issue": "CRITICAL: No compensation/rollback. CartService calls OrderService first, then PaymentService. If payment fails (or times out), the order and inventory reservation are orphaned. There is no saga, no compensation transaction, and no retry logic between the two calls. This will leak reserved inventory on every payment failure."
      }
    ],
    "contract_compliance": "Timeout contracts are misaligned across the call chain. CartService's 5s timeout is shorter than the worst-case latency of both downstream services (OrderService: up to 6s via InventoryService retry; PaymentService: up to 8s via gateway). This violates the principle that caller timeouts must exceed callee timeouts.",
    "data_flow_integrity": "Compromised. The sequential order-then-pay flow with no compensation means any failure in the second call (PaymentService) leaves the system in an inconsistent state: order created, inventory reserved, but no payment. There is no mechanism to detect or reconcile this drift."
  },

  "observability_review": {
    "logging": {
      "coverage": "gaps",
      "gaps": [
        "No mention of correlation/request IDs across the three services — debugging a checkout failure requires manually correlating logs by timestamp",
        "No structured logging of timeout events with upstream/downstream context",
        "No logging of orphaned orders (order created but payment failed) — the most critical failure mode is invisible"
      ]
    },
    "metrics": {
      "coverage": "gaps",
      "gaps": [
        "No latency percentile tracking (p99) on the CartService→OrderService and CartService→PaymentService calls",
        "No metric for orphaned orders or inventory reservation leaks",
        "No circuit breaker state change metrics (open/closed/half-open transitions)",
        "No metric tracking effective timeout rate vs actual downstream errors"
      ]
    },
    "tracing": {
      "coverage": "gaps",
      "gaps": [
        "No distributed tracing mentioned across the 4-service call chain (Cart→Order→Inventory, Cart→Payment→Gateway)",
        "Without tracing, diagnosing whether a checkout failure was caused by InventoryService, PaymentGateway, or network is guesswork"
      ]
    },
    "debugging_capability": "Poor. An on-call engineer at 3am seeing 'checkout failed' has no way to determine which service in the chain caused the failure, whether inventory was reserved but payment failed, or whether the failure was a true error vs. a timeout race. The orphaned-order scenario is completely silent."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "Payment gateway slow (>5s but <8s)",
        "handling": "unhandled",
        "recommendation": "CartService times out at 5s, but PaymentService continues processing and may charge the customer. Reduce PaymentService gateway timeout to 4s (below CartService's 5s) OR implement idempotent payment with reconciliation."
      },
      {
        "scenario": "PaymentService fails after OrderService succeeds",
        "handling": "unhandled",
        "recommendation": "CRITICAL: Implement a saga pattern or compensation transaction. CartService must call OrderService to cancel/release the order and inventory reservation when payment fails. Without this, every payment failure leaks inventory."
      },
      {
        "scenario": "InventoryService slow (>2.5s)",
        "handling": "partial",
        "recommendation": "OrderService retries (good), but total latency 6s exceeds CartService's 5s timeout. Either remove the retry and fail fast, or increase CartService timeout to 7s+ to accommodate the retry."
      },
      {
        "scenario": "OrderService completely down",
        "handling": "unhandled",
        "recommendation": "No circuit breaker on OrderService. Every checkout attempt will hang for 5s before failing. Add a circuit breaker with appropriate thresholds to fail fast."
      },
      {
        "scenario": "Payment gateway completely down",
        "handling": "partial",
        "recommendation": "CartService has a circuit breaker on PaymentService (good), but PaymentService has no circuit breaker on the gateway. PaymentService will exhaust its connection pool before CartService's breaker trips. Add a circuit breaker inside PaymentService on the gateway call."
      },
      {
        "scenario": "Cascading failure: InventoryService down → OrderService degrades → CartService saturated",
