      ],
      "config_changes": [
        "Align timeout hierarchy: PaymentService gateway timeout ≤ 4s, OrderService InventoryService timeout budget ≤ 4s, CartService caller timeouts ≥ downstream worst-case + buffer",
        "Add circuit breaker config for CartService→OrderService",
        "Add circuit breaker config for PaymentService→Gateway"
      ],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": false,
      "large_table_impact": false,
      "details": "No database migration details provided. However, the orphaned order/inventory reservation issue implies the order and inventory databases will accumulate inconsistent state over time without a reconciliation process."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
